import React, { useEffect, useState, useMemo } from 'react';
import { useTable } from 'react-table';

const MaterialList = () => {
  const [material, setMaterial] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('http://localhost:8081/');
        const data = await response.json();
        setMaterial(data);
      } catch (error) {
        console.log('Error fetching data:', error);
      }
    };

    fetchData();
  }, []);

  const columns = React.useMemo(
    () => [
      { Header: 'MaterialID', accessor : 'matid'},
      { Header: 'Name', accessor : 'name'},
      { Header: 'Description', accessor : 'description'},
      { Header: 'UoM', accessor : 'unit_of_measure'},
      { Header: 'Price/UoM', accessor : 'price_per_unit'},
      { Header: 'Recent Vendor', accessor : 'recent_vendor'}
          ],
    []
  );

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = useTable({
    columns,
    material,
  });

  return (
    <div className="App">
      <h1 style={{ color: 'green' }}>using JavaScript inbuilt FETCH API</h1>
      <center>
        {material.map((materialObj, index) => (
          <div
            key={index}
            style={{
              width: '15em',
              backgroundColor: '#35D841',
              padding: 2,
              borderRadius: 10,
              marginBlock: 10,
            }}
          >
            <p style={{ fontSize: 20, color: 'white' }}>{materialObj.name}</p>
          </div>
        ))}
      </center>
    </div>
  );
};

export default MaterialList;
